    74	export async function handleValidateMilestone(
    75	  params: ValidateMilestoneParams,
    76	  basePath: string,
    77	): Promise<ValidateMilestoneResult | { error: string }> {
    78	  if (!params.milestoneId || typeof params.milestoneId !== "string" || params.milestoneId.trim() === "") {
    79	    return { error: "milestoneId is required and must be a non-empty string" };
    80	  }
    81	  if (!isValidMilestoneVerdict(params.verdict)) {
    82	    return { error: `verdict must be one of: ${VALIDATION_VERDICTS.join(", ")}` };
    83	  }
    84	
    85	  // ── Resolve paths and render markdown ────────────────────────────────
    86	  const validationMd = renderValidationMarkdown(params);
    87	
    88	  let validationPath: string;
    89	  const milestoneDir = resolveMilestonePath(basePath, params.milestoneId);
    90	  if (milestoneDir) {
    91	    validationPath = join(milestoneDir, `${params.milestoneId}-VALIDATION.md`);
    92	  } else {
    93	    const gsdDir = join(basePath, ".gsd");
    94	    const manualDir = join(gsdDir, "milestones", params.milestoneId);
    95	    validationPath = join(manualDir, `${params.milestoneId}-VALIDATION.md`);
    96	  }
    97	
    98	  // ── DB write first — matches complete-task/complete-slice pattern ───
    99	  // Write DB before disk so a crash between the two leaves a recoverable
   100	  // state: the DB row exists but the file is missing, which projection
   101	  // rendering can regenerate. The inverse (file exists, no DB row) is
   102	  // harder to detect and recover from (#2725).
   103	  const validatedAt = new Date().toISOString();
   104	
   105	  transaction(() => {
   106	    insertAssessment({
   107	      path: validationPath,
   108	      milestoneId: params.milestoneId,
   109	      sliceId: null,
   110	      taskId: null,
   111	      status: params.verdict,
   112	      scope: 'milestone-validation',
   113	      fullContent: validationMd,
   114	    });
   115	  });
   116	
   117	  // ── Filesystem render (outside transaction) ────────────────────────────
   118	  // If disk render fails, roll back the DB row so state stays consistent.
   119	  try {
   120	    await saveFile(validationPath, validationMd);
   121	  } catch (renderErr) {
   122	    process.stderr.write(
   123	      `gsd-db: validate_milestone — disk render failed, rolling back DB row: ${(renderErr as Error).message}\n`,
   124	    );
   125	    deleteAssessmentByScope(params.milestoneId, 'milestone-validation');
   126	    return { error: `disk render failed: ${(renderErr as Error).message}` };
   127	  }
   128	
   129	  invalidateStateCache();
   130	  clearPathCache();
   131	  clearParseCache();
   132	
   133	  return {
   134	    milestoneId: params.milestoneId,
   135	    verdict: params.verdict,
   136	    validationPath,
   137	  };
   138	}

