    id: sliceId,
    title,
    done,
    planPath,
    summaryPath,
    uatPath,
    tasksDir,
    branch: getSliceBranchName(milestoneId, sliceId, detectWorktreeName(basePath)),
    risk: roadmapMeta?.risk,
    depends: roadmapMeta?.depends,
    demo: roadmapMeta?.demo,
    tasks,
