  }
  try {
    child?.stdout?.destroy();
  } catch {
    // Ignore cleanup failures.
  }
  try {
    child?.stderr?.destroy();
  } catch {
    // Ignore cleanup failures.
  }
}

function getBridgeDeps(): BridgeServiceDeps {
