          Workspace freshness: {workspaceFreshness}
        </p>
      </div>

      <div className="flex-1 overflow-y-auto p-6">
        {workspace.bootStatus === "loading" && (
          <div className="py-8 text-center text-sm text-muted-foreground">Loading workspace…</div>
